//#region src/utils/format-validation-issues.ts
function formatPath(path) {
	if (!path || path.length === 0) return "";
	let out = "";
	for (const segment of path) {
		const key = typeof segment === "object" && segment !== null && "key" in segment ? segment.key : segment;
		if (typeof key === "number") out += `[${key}]`;
		else if (key !== void 0 && key !== null) out += out === "" ? String(key) : `.${String(key)}`;
	}
	return out;
}
function summarizeIssue(issue) {
	const path = formatPath(issue.path);
	if (issue.kind === "schema" && (issue.type === "object" || issue.type === "strict_object" || issue.type === "loose_object") && typeof issue.expected === "string" && issue.expected.length >= 2 && issue.expected.startsWith("\"") && issue.expected.endsWith("\"") && issue.received === "undefined") {
		const field = issue.expected.slice(1, -1);
		const parentPathStr = formatPath((issue.path ?? []).slice(0, -1));
		return {
			path,
			message: `Missing required field \`${field}\`${parentPathStr ? ` at \`${parentPathStr}\`` : ""}.`
		};
	}
	return {
		path,
		message: issue.message
	};
}
/**
* Wrap a standard-schema validator so that validation failures contain
* trimmed, agent-readable issue objects instead of raw valibot metadata.
*
* Successful inputs pass through unchanged (we don't touch the parsed value).
*
* Standard Schema validators are POJOs by convention (data fields + a
* `~standard` slot, no prototype methods), so spread-and-replace is enough
* — no Proxy required.
*/
function withFriendlyErrors(schema) {
	const original = schema["~standard"];
	return {
		...schema,
		"~standard": {
			...original,
			validate(input) {
				const result = original.validate(input);
				const trim = (r) => r.issues ? { issues: r.issues.map(summarizeIssue) } : r;
				return result instanceof Promise ? result.then(trim) : trim(result);
			}
		}
	};
}

