const ReviewCollectionSchema = v.object({
	title: v.pipe(v.string(), v.description("Title describing **what** this collection consists of, phrased the way a person would say it. Avoid typographic marks and CamelCase. Plain text, no markdown.")),
	rationale: v.pipe(v.string(), v.description("Rationale explaining **why** this collection is relevant to the user. Shown alongside the title. One or two sentences. Plain text, no markdown.")),
	storyIds: v.pipe(v.array(v.string()), v.description("Story IDs that represent this collection (e.g. \"button--primary\"). The page renders exactly these."))
});
const ReviewStateSchema = v.object({
	title: v.pipe(v.string(), v.description("Terse, human-readable title for the overall review. What is this review about? Avoid typographic marks and CamelCase. Plain text, no markdown.")),
	description: v.pipe(v.string(), v.description("Description of the review scope, including what's there, why it's relevant, and what to look for. Preferably one or two sentences. At most 2 paragraphs for reviews spanning multiple topics. Markdown formatting restricted to **bold**, _italic_, and `code` (backticks). Use emphasis for the key **what** and _why_, and backticks for literal source code references like component or token names.")),
	collections: v.pipe(v.array(ReviewCollectionSchema), v.description("Groups of stories to show in the review, most relevant first. Prefer 2-5 groups.")),
	changedFiles: v.pipe(v.array(v.string()), v.description("Paths of the files you changed, most central first. Pass an empty array `[]` only when no code changed (browse requests, Trigger 2)."))
});
const DisplayReviewOutput = v.object({ reviewUrl: v.pipe(v.string(), v.description("URL of the Storybook review page. Always include this URL in your final user-facing response so the user can open it directly.")) });
