//#region src/tools/tool-registry.ts
const isToolsetEnabled = (toolset, toolsets) => toolsets?.[toolset] ?? true;
const isToolAvailable = (definition, context) => definition.available?.(context) ?? true;
const isMetadataToolEnabled = (definition, context) => isToolsetEnabled(definition.toolset, context.toolsets) && isToolAvailable(definition, context);
const createToolsetEnabled = (server, toolset) => () => server.ctx.custom?.toolsets?.[toolset] ?? true;
const addonToolDefinitions = [
	{
		name: PREVIEW_STORIES_TOOL_NAME,
		toolset: "dev",
		getMetadata: ({ availability }) => getPreviewStoriesToolMetadata({ reviewEnabled: availability.reviewEnabled }),
		register: (server, { availability }, enabled) => addPreviewStoriesTool(server, enabled, { reviewEnabled: availability.reviewEnabled })
	},
	{
		name: GET_UI_BUILDING_INSTRUCTIONS_TOOL_NAME,
		toolset: "dev",
		getMetadata: ({ availability, toolsets }) => {
			const testToolsetAvailable = isToolsetEnabled("test", toolsets) && availability.testSupported;
			return getStorybookStoryInstructionsToolMetadata({
				testToolsetAvailable,
				a11yAvailable: testToolsetAvailable && availability.a11yEnabled
			});
		},
		register: (server, { availability, toolsets }, enabled) => addGetUIBuildingInstructionsTool(server, enabled, { docsAvailable: isToolsetEnabled("docs", toolsets) && availability.docsEnabled }),
		getLocalTool: ({ availability, toolsets, options }) => ({ call: async () => {
			return { content: [{
				type: "text",
				text: await buildStorybookStoryInstructions(options, {
					toolsets,
					a11yEnabled: availability.a11yEnabled,
					addonVitestAvailable: availability.testSupported,
					docsAvailable: isToolsetEnabled("docs", toolsets) && availability.docsEnabled,
					reviewEnabled: availability.reviewEnabled
				})
			}] };
		} })
	},
	{
		name: GET_CHANGED_STORIES_TOOL_NAME,
		toolset: "dev",
		available: ({ availability }) => availability.changeDetectionEnabled,
		getMetadata: () => getChangedStoriesToolMetadata(),
		register: (server, { availability }, enabled) => addGetChangedStoriesTool(server, enabled, { reviewEnabled: availability.reviewEnabled })
	},
	{
		name: GET_STORIES_BY_COMPONENT_TOOL_NAME,
		toolset: "dev",
		available: ({ availability }) => availability.moduleGraphSupported,
		getMetadata: ({ availability }) => getStoriesByComponentToolMetadata({ reviewEnabled: availability.reviewEnabled }),
		register: (server, { availability }, enabled) => addGetStoriesByComponentTool(server, enabled, { reviewEnabled: availability.reviewEnabled })
	},
	{
		name: DISPLAY_REVIEW_TOOL_NAME,
		toolset: "dev",
		available: ({ availability }) => availability.reviewEnabledForCli,
		getMetadata: () => getDisplayReviewToolMetadata(),
		register: (server, { availability }, enabled) => addDisplayReviewTool(server, async () => (await enabled?.() ?? true) && (server.ctx.custom?.reviewEnabled ?? availability.reviewEnabled))
	},
	{
		name: RUN_STORY_TESTS_TOOL_NAME,
		toolset: "test",
		available: ({ availability }) => availability.testSupported,
		getMetadata: ({ availability }) => getRunStoryTestsToolMetadata({ a11yEnabled: availability.a11yEnabled }),
		register: (server, { availability }, enabled) => addRunStoryTestsTool(server, { a11yEnabled: availability.a11yEnabled }, enabled)
	},
	{
		name: LIST_TOOL_NAME,
		toolset: "docs",
		available: ({ availability }) => availability.docsEnabled,
		getMetadata: () => getListAllDocumentationToolMetadata(),
		register: async (server, _context, enabled) => {
			logger.info("Experimental components manifest feature detected - registering component tools");
			await addListAllDocumentationTool(server, enabled);
		}
	},
	{
		name: GET_TOOL_NAME,
		toolset: "docs",
		available: ({ availability }) => availability.docsEnabled,
		getMetadata: ({ multiSource }) => getDocumentationToolMetadata({ multiSource }),
		register: (server, { multiSource }, enabled) => addGetDocumentationTool(server, enabled, { multiSource })
	},
	{
		name: GET_STORY_TOOL_NAME,
		toolset: "docs",
		available: ({ availability }) => availability.docsEnabled,
		getMetadata: ({ multiSource }) => getStoryDocumentationToolMetadata({ multiSource }),
		register: (server, { multiSource }, enabled) => addGetStoryDocumentationTool(server, enabled, { multiSource })
	}
];
function getAddonToolMetadata(context) {
	return addonToolDefinitions.filter((definition) => isMetadataToolEnabled(definition, context)).map((definition) => definition.getMetadata(context));
}
function getAddonLocalTools(context) {
	return Object.fromEntries(addonToolDefinitions.filter((definition) => isMetadataToolEnabled(definition, context)).flatMap((definition) => {
		const localTool = definition.getLocalTool?.(context);
		return localTool ? [[definition.name, localTool]] : [];
	}));
}
async function registerAddonMcpTools(server, context) {
	for (const definition of addonToolDefinitions) if (isToolsetEnabled(definition.toolset, context.toolsets) && isToolAvailable(definition, context)) await definition.register(server, context, createToolsetEnabled(server, definition.toolset));
}

